// ─── EFEIA Cuestionario A: Preparar payload Klaviyo ───────────────
const body = $input.first().json.body ?? $input.first().json;

const email     = (body.email     || '').trim();
const nombre    = (body.nombre    || '').trim();
const whatsapp  = (body.whatsapp  || '').trim();
const wa_opt    = body.wa_opt === true;
const respuestas = body.respuestas || {};
const fecha     = body.fecha || new Date().toISOString();

// Prefijo ca_ para distinguir de otras propiedades en Klaviyo
const caProps = {};
for (const [k, v] of Object.entries(respuestas)) {
  caProps[`ca_${k}`] = Array.isArray(v) ? v.join(', ') : v;
}

const profileAttributes = {
  email,
  first_name: nombre,
  properties: {
    ...caProps,
    whatsapp,
    wa_opt
  }
};

if (whatsapp && whatsapp.length > 4) {
  profileAttributes.phone_number = whatsapp;
}

const klaviyoPayload = {
  data: {
    type: 'event',
    attributes: {
      time: fecha,
      metric: {
        data: {
          type: 'metric',
          attributes: { name: 'Cuestionario_A_Completado' }
        }
      },
      profile: {
        data: {
          type: 'profile',
          attributes: profileAttributes
        }
      },
      properties: {
        ...caProps,
        nombre,
        whatsapp
      }
    }
  }
};

return [{ json: { klaviyoPayload, email, nombre, whatsapp } }];
